import json
import boto3
from botocore.exceptions import ClientError
import logging

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

def lambda_handler(event, context):
    # Initialize clients
    s3_client = boto3.client('s3')
    sns_client = boto3.client('sns')
    
    # Extract bucket and key from S3 event
    try:
        bucket = event['Records'][0]['s3']['bucket']['name']
        key = event['Records'][0]['s3']['object']['key']
        logger.info(f"Processing file: {key} from bucket: {bucket}")
    except KeyError as e:
        logger.error(f"Error extracting S3 event data: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps('Error processing S3 event')
        }
    
    try:
        # Read image from S3
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response['Body'].read()
        
        # Process image (placeholder for actual processing)
        # In a real implementation, this would be your image processing logic
        processed_image_data = image_data  # Placeholder
        
        # Generate output key
        output_key = f"processed/{key}"
        
        # Write processed image back to S3
        s3_client.put_object(
            Bucket=bucket,
            Key=output_key,
            Body=processed_image_data,
            ContentType='image/jpeg'
        )
        
        # Send SNS notification
        topic_arn = 'arn:aws:sns:us-east-1:123456789012:image-processing-complete'
        sns_client.publish(
            TopicArn=topic_arn,
            Subject='Image Processing Complete',
            Message=f'Processed image {key} and saved to {output_key}'
        )
        
        logger.info(f"Successfully processed and saved {output_key}")
        
        return {
            'statusCode': 200,
            'body': json.dumps('Image processed successfully')
        }
        
    except ClientError as e:
        logger.error(f"Error processing image: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps('Error processing image')
        }
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps('Unexpected error')
        }

